<script setup lang="ts">
import { computed, onMounted, onUnmounted, ref, watchEffect } from 'vue';

type Mode = 'auto' | 'day' | 'night';
type Theme = 'day' | 'night';

const PREF_KEY = 'msp_v5:theme_mode';
const DAY_START = 6;
const DAY_END = 18;

function getStoredMode(): Mode {
  try {
    const v = localStorage.getItem(PREF_KEY);
    return v === 'day' || v === 'night' || v === 'auto' ? v : 'auto';
  } catch {
    return 'auto';
  }
}
function setStoredMode(v: Mode) {
  try {
    localStorage.setItem(PREF_KEY, v);
  } catch {
    /* noop */
  }
}

function isDaytime(date: Date): boolean {
  const h = date.getHours();
  return h >= DAY_START && h < DAY_END;
}

const mode = ref<Mode>(getStoredMode());
const now = ref(new Date());
let timer: number | null = null;

const effectiveTheme = computed<Theme>(() => {
  if (mode.value === 'auto') return isDaytime(now.value) ? 'day' : 'night';
  return mode.value;
});

function applyTheme(theme: Theme) {
  document.documentElement.setAttribute('data-theme', theme);
}

watchEffect(() => applyTheme(effectiveTheme.value));

function setMode(m: Mode) {
  mode.value = m;
  setStoredMode(m);
}

const modeLabel = computed(() => {
  if (mode.value === 'auto') return `自动 · ${effectiveTheme.value === 'day' ? '日间' : '夜间'}`;
  return mode.value === 'day' ? '日间' : '夜间';
});

onMounted(() => {
  timer = window.setInterval(() => {
    now.value = new Date();
  }, 60_000);
});

onUnmounted(() => {
  if (timer !== null) window.clearInterval(timer);
});
</script>

<template>
  <div class="theme-toggle" role="radiogroup" aria-label="主题模式">
    <button
      class="seg"
      :class="{ active: mode === 'auto' }"
      type="button"
      role="radio"
      :aria-checked="mode === 'auto'"
      title="跟随时间"
      aria-label="跟随时间"
      @click="setMode('auto')"
    >
      <svg viewBox="0 0 24 24" aria-hidden="true">
        <path
          d="M12 4V2M12 22v-2M4 12H2M22 12h-2M5.6 5.6L4.2 4.2M19.8 19.8l-1.4-1.4M5.6 18.4l-1.4 1.4M19.8 4.2l-1.4 1.4"
          stroke="currentColor"
