          stroke="currentColor"
          stroke-width="1.8"
          stroke-linecap="round"
          fill="none"
        />
      </svg>
    </button>
    <button
      class="seg"
      :class="{ active: mode === 'night' }"
      type="button"
      role="radio"
      :aria-checked="mode === 'night'"
      title="夜间"
      aria-label="夜间"
      @click="setMode('night')"
    >
      <svg viewBox="0 0 24 24" aria-hidden="true">
        <path
          d="M21 12.8A9 9 0 1 1 11.2 3a7 7 0 0 0 9.8 9.8z"
