<script setup lang="ts">
import { computed } from 'vue';

interface Attr {
  grade: string;
  note: string;
}

const props = defineProps<{
  data: Record<string, Attr>;
}>();

const ATTR_ORDER = [
  '基准值',
  '发动值',
  '集束性',
  '扩散性',
  '操纵性',
  '付属性',
  '维持性',
  '干涉性',
] as const;

// 等级 → 0..1 数值 (用于进度条长度)
const GRADE_VALUE: Record<string, number> = {
  E: 0.15,
  'E-': 0.1,
  'E+': 0.22,
  D: 0.3,
  'D-': 0.25,
  'D+': 0.38,
  C: 0.45,
  'C-': 0.4,
  'C+': 0.52,
  B: 0.6,
  'B-': 0.55,
  'B+': 0.66,
  A: 0.74,
  'A-': 0.7,
  'A+': 0.8,
  AA: 0.86,
  'AA-': 0.82,
  'AA+': 0.9,
  AAA: 0.94,
  'AAA-': 0.92,
  'AAA+': 0.97,
  EX: 1,
  'EX+': 1,
};

function gradeToValue(grade: string): number {
  const g = grade.trim().toUpperCase();
  if (!g || g === '—') return 0.1;
  if (GRADE_VALUE[g] !== undefined) return GRADE_VALUE[g];

  // range like "B~A" or "C/D" or "E++~A++"
  const range = g.match(/^([A-Z+-]+)[~/]([A-Z+-]+)$/);
  if (range) {
    const a = GRADE_VALUE[range[1]] ?? 0.3;
    const b = GRADE_VALUE[range[2]] ?? 0.7;
    return (a + b) / 2;
  }

  if (g.endsWith('++')) {
    const base = GRADE_VALUE[g.slice(0, -2)] ?? 0.4;
    return Math.min(1, base + 0.08);
  }

  const tokens = g.split(/[\s/~]/);
  for (const t of tokens) {
    if (GRADE_VALUE[t] !== undefined) return GRADE_VALUE[t];
  }
  return 0.2;
}

const GRADE_COLOR: Record<string, string> = {
  E: 'var(--grade-e)',
  D: 'var(--grade-d)',
  C: 'var(--grade-c)',
  B: 'var(--grade-b)',
  A: 'var(--grade-a)',
  AA: 'var(--grade-aa)',
  AAA: 'var(--grade-aaa)',
  EX: 'var(--grade-ex)',
};

function gradeColor(grade: string): string {
  const g = grade.trim().toUpperCase();
  if (!g || g === '—') return 'var(--grade-e)';
  const m = g.match(/^(AAA|AA|A|B|C|D|E|EX)/);
  if (m && GRADE_COLOR[m[1]]) return GRADE_COLOR[m[1]];
  return 'var(--grade-e)';
}

interface Tile {
  name: string;
  grade: string;
  note: string;
  value: number;
  color: string;
}

const tiles = computed<Tile[]>(() =>
  ATTR_ORDER.map(name => {
    const attr = props.data[name];
    const grade = attr?.grade ?? '—';
    const note = attr?.note ?? '';
    return {
      name,
      grade,
      note,
      value: gradeToValue(grade),
      color: gradeColor(grade),
    };
  }),
);

const hasNotes = computed(() => tiles.value.some(t => t.note));
</script>

<template>
  <div class="ability-grid">
    <div class="grid">
      <div
        v-for="t in tiles"
        :key="t.name"
        class="tile"
        :style="{ '--gc': t.color }"
        :title="t.note || undefined"
      >
        <div class="tile-head">
          <span class="tile-name">{{ t.name }}</span>
          <span class="tile-grade mono" :style="{ color: t.color }">{{ t.grade }}</span>
        </div>
        <div class="tile-bar">
          <div
            class="bar-fill"
            :style="{ width: t.value * 100 + '%', background: t.color }"
          />
        </div>
      </div>
    </div>

    <details v-if="hasNotes" class="notes">
      <summary>能力注解</summary>
      <ul>
        <li v-for="t in tiles.filter(x => x.note)" :key="t.name">
          <span class="note-name" :style="{ color: t.color }">{{ t.name }}</span>
          <span class="note-grade mono">{{ t.grade }}</span>
          <span class="note-text">{{ t.note }}</span>
        </li>
      </ul>
    </details>
  </div>
</template>

