<script setup lang="ts">
import { computed } from 'vue';

type Variant = 'default' | 'primary' | 'mako' | 'fallen' | 'ghost';
type Chamfer = 'tl-br' | 'all' | 'none';
type Density = 'compact' | 'normal' | 'wide';

const props = withDefaults(
  defineProps<{
    variant?: Variant;
    chamfer?: Chamfer;
    density?: Density;
    brackets?: boolean;
    glow?: boolean;
    as?: string;
  }>(),
  {
    variant: 'default',
    chamfer: 'tl-br',
    density: 'normal',
    brackets: false,
    glow: false,
    as: 'div',
  },
);

const chamferSize = computed(() => {
  switch (props.density) {
    case 'compact':
      return '8px';
    case 'wide':
      return '22px';
    default:
      return '14px';
  }
});

const clipPath = computed(() => {
  const c = chamferSize.value;
  if (props.chamfer === 'none') return 'none';
  if (props.chamfer === 'all') {
    return `polygon(${c} 0, calc(100% - ${c}) 0, 100% ${c}, 100% calc(100% - ${c}), calc(100% - ${c}) 100%, ${c} 100%, 0 calc(100% - ${c}), 0 ${c})`;
  }
  // tl-br (default): cut top-left + bottom-right
  return `polygon(${c} 0, 100% 0, 100% calc(100% - ${c}), calc(100% - ${c}) 100%, 0 100%, 0 ${c})`;
});

const pad = computed(() => {
  switch (props.density) {
    case 'compact':
      return '8px 10px';
    case 'wide':
      return '18px 20px';
    default:
      return '12px 14px';
  }
});

const variantClass = computed(() => `v-${props.variant}`);
</script>

<template>
  <component
    :is="as"
    class="chamfer"
    :class="[variantClass, { glow: glow, 'has-brackets': brackets }]"
    :style="{ '--cs': chamferSize, '--cp': clipPath, '--pad': pad }"
  >
    <span v-if="brackets" class="bracket br-tl" aria-hidden="true" />
    <span v-if="brackets" class="bracket br-tr" aria-hidden="true" />
    <span v-if="brackets" class="bracket br-bl" aria-hidden="true" />
    <span v-if="brackets" class="bracket br-br" aria-hidden="true" />
    <slot />
  </component>
</template>

<style scoped>
.chamfer {
  position: relative;
  clip-path: var(--cp);
  background: var(--panel-glass);
  padding: var(--pad);
  border: 1px solid var(--border);
  transition:
    border-color var(--dur-fast) var(--ease-out),
    background var(--dur-fast) var(--ease-out);
}

/* 因为 clip-path 会切掉 box-shadow, 用外层包装或 filter:drop-shadow 替代 */
.chamfer.glow {
  filter: drop-shadow(0 0 12px var(--accent-glow));
}

.v-default {
  background: var(--panel-glass);
  border-color: var(--border);
}
.v-primary {
  background: linear-gradient(135deg, var(--panel-strong) 0%, var(--panel-glass) 100%);
  border-color: var(--border-strong);
}
.v-mako {
  background: linear-gradient(135deg, var(--mako-soft) 0%, var(--panel-glass) 60%);
  border-color: var(--mako-glow);
}
.v-fallen {
  background: linear-gradient(135deg, var(--fallen-soft) 0%, var(--panel-glass) 60%);
  border-color: var(--fallen-glow);
}
.v-ghost {
  background: transparent;
  border-color: var(--border-weak);
  backdrop-filter: none;
}

/* FF 角括号装饰 */
.has-brackets .bracket {
  position: absolute;
  width: 10px;
  height: 10px;
  pointer-events: none;
  z-index: 1;
}
.has-brackets .br-tl {
  top: 3px;
  left: 3px;
  border-top: 1.5px solid var(--accent);
  border-left: 1.5px solid var(--accent);
}
.has-brackets .br-tr {
  top: 3px;
  right: 3px;
  border-top: 1.5px solid var(--accent);
  border-right: 1.5px solid var(--accent);
}
.has-brackets .br-bl {
  bottom: 3px;
  left: 3px;
  border-bottom: 1.5px solid var(--accent);
  border-left: 1.5px solid var(--accent);
}
.has-brackets .br-br {
  bottom: 3px;
  right: 3px;
  border-bottom: 1.5px solid var(--accent);
  border-right: 1.5px solid var(--accent);
}
.v-mako.has-brackets .bracket {
  border-color: var(--mako);
}
.v-fallen.has-brackets .bracket {
  border-color: var(--fallen);
}
</style>
