<script setup lang="ts">
import { computed, nextTick, provide, ref } from 'vue';
import ChamferPanel from './components/ChamferPanel.vue';
import Clock from './components/Clock.vue';
import SectionNav from './components/SectionNav.vue';
import ThemeToggle from './components/ThemeToggle.vue';
import PartySection from './pages/PartySection.vue';
import PlayerSection from './pages/PlayerSection.vue';
import ArchiveSection from './pages/ArchiveSection.vue';
import { useDataStore } from './store';

const store = useDataStore();

const SECTIONS = [
  { id: 'party', label: '在场' },
  { id: 'player', label: '渡鸦' },
  { id: 'archive', label: '档案' },
] as const;

const PREF_KEY = 'msp_v5:active_section';
function getStoredSection(): string {
  try {
    const v = localStorage.getItem(PREF_KEY);
    return v && SECTIONS.some(s => s.id === v) ? v : 'party';
  } catch {
    return 'party';
  }
}
function setStoredSection(v: string) {
  try {
    localStorage.setItem(PREF_KEY, v);
  } catch {
    /* noop */
  }
}

const activeSection = ref<string>(getStoredSection());

function switchSection(id: string) {
  activeSection.value = id;
  setStoredSection(id);
}

// ── 跨分区跳转 (从在场角色跳到档案) ──
const selectGirlRef = ref<string | null>(null);

async function jumpToGirl(key: string) {
  selectGirlRef.value = key;
  // 先切到档案分区, 再触发选中信号
  switchSection('archive');
  await nextTick();
  // 信号在 300ms 后清理, 让 ArchiveSection 有时间响应
  setTimeout(() => {
    selectGirlRef.value = null;
  }, 300);
}

provide('jumpToGirl', jumpToGirl);
provide('selectGirlEvent', selectGirlRef);

const locationText = computed(() => {
  const loc = (store.data as Record<string, unknown>).地点 as
    | { 城市?: string; 地区?: string; 地址?: string }
    | undefined;
  return [loc?.城市?.trim() || '新都', loc?.地区?.trim() || '未知地区', loc?.地址?.trim() || '未知地点']
    .filter(Boolean)
    .join(' · ');
});
</script>

<template>
  <div class="shell scanlines">
    <!-- Sticky Header -->
    <header class="header">
      <ChamferPanel variant="primary" density="compact" chamfer="none" class="header-inner">
        <div class="header-row">
          <div class="loc-block">
            <span class="loc-icon" aria-hidden="true">◆</span>
            <span class="loc-eyebrow">LOC</span>
            <span class="loc-text">{{ locationText }}</span>
          </div>
          <div class="header-tools">
            <Clock />
            <ThemeToggle />
          </div>
        </div>
        <SectionNav
          :sections="[...SECTIONS]"
          :model-value="activeSection"
          class="nav-row"
          @update:model-value="switchSection"
        />
      </ChamferPanel>
    </header>

    <!-- Single Active Section -->
    <main class="main">
      <PartySection v-if="activeSection === 'party'" />
      <PlayerSection v-else-if="activeSection === 'player'" />
      <ArchiveSection v-else-if="activeSection === 'archive'" />
    </main>
  </div>
</template>

