<script setup lang="ts">
import { computed, nextTick, ref, watch } from 'vue';

type Type = 'text' | 'textarea';

const props = withDefaults(
  defineProps<{
    modelValue: string;
    type?: Type;
    placeholder?: string;
    multiline?: boolean;
    emptyText?: string;
    mono?: boolean;
    editOnHover?: boolean;
    disabled?: boolean;
  }>(),
  {
    type: 'text',
    placeholder: '',
    multiline: false,
    emptyText: '',
    mono: false,
    editOnHover: false,
    disabled: false,
  },
);

const emit = defineEmits<{
  'update:modelValue': [value: string];
  save: [value: string];
  cancel: [];
}>();

const isEditing = ref(false);
const draft = ref(props.modelValue);
const inputEl = ref<HTMLInputElement | HTMLTextAreaElement | null>(null);

watch(
  () => props.modelValue,
  v => {
    if (!isEditing.value) draft.value = v;
  },
);

async function startEdit() {
  if (props.disabled || isEditing.value) return;
  draft.value = props.modelValue;
  isEditing.value = true;
  await nextTick();
  inputEl.value?.focus();
  if (props.type === 'textarea') {
    (inputEl.value as HTMLTextAreaElement)?.select?.();
  } else {
    (inputEl.value as HTMLInputElement)?.select?.();
  }
}

function commit() {
  const v = draft.value;
  isEditing.value = false;
  if (v !== props.modelValue) {
    emit('update:modelValue', v);
    emit('save', v);
  }
}

function cancel() {
  isEditing.value = false;
  draft.value = props.modelValue;
  emit('cancel');
}

function onKeydown(e: KeyboardEvent) {
  if (e.key === 'Enter' && !props.multiline) {
    e.preventDefault();
    commit();
  } else if (e.key === 'Enter' && (e.ctrlKey || e.metaKey) && props.multiline) {
    e.preventDefault();
    commit();
  } else if (e.key === 'Escape') {
    e.preventDefault();
    cancel();
  }
}

const displayText = computed(() => {
  const t = props.modelValue?.trim();
  return t || props.emptyText || props.placeholder || '—';
});

const isEmpty = computed(() => !props.modelValue?.trim());
</script>

<template>
  <span class="inline-edit" :class="{ mono }">
    <template v-if="!isEditing">
      <button
        class="display"
        type="button"
        :class="{ empty: isEmpty }"
        :disabled="disabled"
        @click="startEdit"
      >
        <span class="text">{{ displayText }}</span>
        <svg class="pen" viewBox="0 0 24 24" aria-hidden="true">
          <path
            d="M5 19l1-5 12-12 4 4-12 12-5 1z"
            fill="none"
            stroke="currentColor"
            stroke-width="1.6"
            stroke-linejoin="round"
          />
        </svg>
      </button>
    </template>
    <span v-else class="editor">
      <textarea
        v-if="type === 'textarea'"
        ref="inputEl"
        v-model="draft"
        class="field area"
        :placeholder="placeholder"
        rows="3"
        @keydown="onKeydown"
      />
      <input
        v-else
        ref="inputEl"
        v-model="draft"
        class="field"
        type="text"
        :placeholder="placeholder"
        @keydown="onKeydown"
      />
      <span class="actions">
        <button class="btn-ok" type="button" title="保存 (Enter)" aria-label="保存" @click="commit">
          <svg viewBox="0 0 24 24" aria-hidden="true">
            <path d="M5 12l5 5L20 7" fill="none" stroke="currentColor" stroke-width="2.4" stroke-linecap="round" stroke-linejoin="round" />
          </svg>
        </button>
        <button class="btn-no" type="button" title="取消 (Esc)" aria-label="取消" @click="cancel">
          <svg viewBox="0 0 24 24" aria-hidden="true">
            <path d="M6 6l12 12M18 6L6 18" fill="none" stroke="currentColor" stroke-width="2.4" stroke-linecap="round" />
          </svg>
        </button>
      </span>
    </span>
  </span>
</template>

