<script setup lang="ts">
import { computed, reactive, ref, watchEffect } from 'vue';
import ChamferPanel from '../components/ChamferPanel.vue';
import InlineEdit from '../components/InlineEdit.vue';
import { useDataStore } from '../store';

const store = useDataStore();

// ── Identity (inline edit) ──
const identity = computed({
  get: () => (((store.data as Record<string, unknown>).渡鸦 as Record<string, unknown>).身份 as string) ?? '',
  set: (v: string) => {
    (((store.data as Record<string, unknown>).渡鸦 as Record<string, unknown>).身份 as string) = v;
  },
});

// ── Skills ──
interface SkillEntry {
  name: string;
  desc: string;
}

const skills = computed<SkillEntry[]>(() => {
  const all = ((store.data.渡鸦 as Record<string, unknown>).技能 as Record<string, { 说明: string }>) ?? {};
  return Object.entries(all)
    .map(([name, s]) => ({ name, desc: s?.说明 ?? '' }))
    .sort((a, b) => a.name.localeCompare(b.name, 'zh-Hans-CN'));
});

// Edit state: which skill is being edited, or 'new' for adding
const editingMode = ref<'idle' | 'new' | 'edit'>('idle');
const editingOriginalName = ref('');
const draft = reactive({ name: '', desc: '' });

const skillMap = computed(() => (store.data.渡鸦.技能 as Record<string, { 说明: string }>) ?? {});

function resetDraft() {
  draft.name = '';
  draft.desc = '';
  editingOriginalName.value = '';
}

function startAdd() {
  resetDraft();
  editingMode.value = 'new';
}

function startEdit(s: SkillEntry) {
  draft.name = s.name;
  draft.desc = s.desc;
  editingOriginalName.value = s.name;
  editingMode.value = 'edit';
}

function cancelEdit() {
  editingMode.value = 'idle';
  resetDraft();
}

function commitSkill() {
  const name = draft.name.trim();
  if (!name) return;

  // 如果是编辑且改名, 先删旧
  if (editingMode.value === 'edit' && editingOriginalName.value && editingOriginalName.value !== name) {
    delete skillMap.value[editingOriginalName.value];
  }
  skillMap.value[name] = { 说明: draft.desc.trim() };
  cancelEdit();
}

function deleteSkill(name: string) {
  if (name in skillMap.value) {
    delete skillMap.value[name];
    if (editingOriginalName.value === name) cancelEdit();
  }
}

watchEffect(() => {
  if (!skills.value.length && editingMode.value === 'edit') cancelEdit();
});

// 选中的技能 (详情显示)
const selectedSkillName = ref<string>('');
watchEffect(() => {
  if (!skills.value.length) {
    selectedSkillName.value = '';
    return;
  }
  if (!skills.value.some(s => s.name === selectedSkillName.value)) {
    selectedSkillName.value = skills.value[0].name;
  }
});

const selectedSkill = computed(() => skills.value.find(s => s.name === selectedSkillName.value) ?? null);
const isLongDesc = computed(() => (selectedSkill.value?.desc?.length ?? 0) > 80);
const descExpanded = ref(false);
watchEffect(() => {
  descExpanded.value = false;
});
</script>

<template>
  <div class="player">
    <!-- Identity -->
    <ChamferPanel variant="mako" density="compact" class="identity-block">
      <div class="row-head">
        <div class="row-titles">
          <div class="row-eyebrow mono">RAVEN · ID</div>
          <div class="row-title">身份</div>
        </div>
      </div>
      <div class="identity-body">
        <InlineEdit
          v-model="identity"
          type="text"
          multiline
          placeholder="点击设置身份描述"
          empty-text="未设置身份"
          class="identity-edit"
        />
      </div>
    </ChamferPanel>

    <!-- Skills -->
    <ChamferPanel variant="default" class="skills-block">
      <div class="row-head">
        <div class="row-titles">
          <div class="row-eyebrow mono">SKILLS</div>
          <div class="row-title">
            技能
            <span class="row-count mono">{{ skills.length }}</span>
          </div>
        </div>
        <button
          v-if="editingMode === 'idle'"
          class="add-btn"
          type="button"
          @click="startAdd"
        >
          <svg viewBox="0 0 24 24" aria-hidden="true">
            <path d="M12 5v14M5 12h14" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" />
          </svg>
          <span>新增</span>
        </button>
      </div>

      <!-- Chips -->
      <div v-if="skills.length" class="chips">
        <button
          v-for="s in skills"
          :key="s.name"
          class="chip"
          :class="{ active: selectedSkillName === s.name && editingMode === 'idle' }"
          type="button"
          :title="s.desc || '暂无说明'"
          @click="selectedSkillName = s.name; editingMode = 'idle'"
          @dblclick="startEdit(s)"
        >
          <span class="chip-name">{{ s.name }}</span>
        </button>
      </div>
      <div v-else-if="editingMode === 'idle'" class="empty-hint">
        尚未掌握任何技能
      </div>

      <!-- Selected skill detail (read mode) -->
      <Transition name="fade">
        <div v-if="selectedSkill && editingMode === 'idle'" class="skill-read">
          <div class="skill-read-head">
            <div class="skill-read-name">{{ selectedSkill.name }}</div>
            <div class="skill-read-actions">
              <button class="mini-btn" type="button" title="编辑" aria-label="编辑" @click="startEdit(selectedSkill)">
                <svg viewBox="0 0 24 24" aria-hidden="true">
                  <path d="M5 19l1-5 12-12 4 4-12 12-5 1z" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linejoin="round" />
                </svg>
              </button>
              <button class="mini-btn danger" type="button" title="删除" aria-label="删除" @click="deleteSkill(selectedSkill.name)">
                <svg viewBox="0 0 24 24" aria-hidden="true">
                  <path d="M6 6l12 12M18 6L6 18" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" />
                </svg>
              </button>
            </div>
          </div>
          <div class="skill-read-desc" :class="{ collapsed: isLongDesc && !descExpanded }">
            {{ selectedSkill.desc || '暂无说明' }}
          </div>
          <button v-if="isLongDesc" class="expand-link" type="button" @click="descExpanded = !descExpanded">
            {{ descExpanded ? '收起' : '展开全部' }}
          </button>
        </div>
      </Transition>

      <!-- Inline edit / add form -->
      <Transition name="slide">
        <div v-if="editingMode !== 'idle'" class="skill-edit">
          <div class="edit-head">
            <div class="edit-title">{{ editingMode === 'new' ? '新增技能' : '编辑技能' }}</div>
            <button class="mini-btn" type="button" title="取消" aria-label="取消" @click="cancelEdit">
              <svg viewBox="0 0 24 24" aria-hidden="true">
                <path d="M6 6l12 12M18 6L6 18" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" />
              </svg>
            </button>
          </div>
          <label class="field">
            <span class="field-label mono">名称</span>
            <input
              v-model="draft.name"
              class="field-input"
              type="text"
              placeholder="例如：幻胧"
              maxlength="40"
              @keydown.enter="commitSkill"
              @keydown.escape="cancelEdit"
            >
          </label>
          <label class="field">
            <span class="field-label mono">说明</span>
            <textarea
              v-model="draft.desc"
              class="field-input area"
              placeholder="技能效果说明"
              rows="3"
              @keydown.escape="cancelEdit"
            />
          </label>
          <div class="edit-actions">
            <button
              class="primary-btn"
              type="button"
              :disabled="!draft.name.trim()"
              @click="commitSkill"
            >
              <svg viewBox="0 0 24 24" aria-hidden="true">
                <path d="M5 12l5 5L20 7" fill="none" stroke="currentColor" stroke-width="2.4" stroke-linecap="round" stroke-linejoin="round" />
              </svg>
              保存
            </button>
            <button
              v-if="editingMode === 'edit'"
              class="danger-btn"
              type="button"
              @click="deleteSkill(editingOriginalName)"
            >
              <svg viewBox="0 0 24 24" aria-hidden="true">
                <path d="M6 7h12M9 7V4h6v3M7 7l1 13h8l1-13" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" />
              </svg>
              删除
            </button>
          </div>
        </div>
      </Transition>
    </ChamferPanel>
  </div>
</template>

