<script setup lang="ts">
import { computed, inject, onMounted, reactive, ref, watchEffect, type Ref } from 'vue';
import AbilityGrid from '../components/AbilityGrid.vue';
import ChamferPanel from '../components/ChamferPanel.vue';
import CrystalOrb from '../components/CrystalOrb.vue';
import StatusBadge from '../components/StatusBadge.vue';
import { expandProtectedNames } from '../magicNames';
import { useDataStore } from '../store';

type Filter = 'all' | 'normal' | 'fallen';

const store = useDataStore();

// ── Mana stage ──
const SURGE = 85;
const HIGH = 60;
const STEADY = 35;
const LOW = 15;
function manaStage(v: number): 'surge' | 'high' | 'steady' | 'low' | 'empty' {
  if (v >= SURGE) return 'surge';
  if (v >= HIGH) return 'high';
  if (v >= STEADY) return 'steady';
  if (v >= LOW) return 'low';
  return 'empty';
}
function attitudeTone(a: string): string {
  const m: Record<string, string> = {
    陌生: 'stranger',
    无关心: 'detached',
    一般: 'neutral',
    信任: 'trust',
    恋心: 'love',
    讨厌: 'dislike',
    死仇: 'hostile',
    爱恨交织: 'conflicted',
  };
  return m[a] || 'neutral';
}

// ── Worldbook parsing ──
const ATTR_NAMES = ['基准值', '发动值', '集束性', '扩散性', '操纵性', '付属性', '维持性', '干涉性'] as const;

function parseMagicAbility(content: string): Record<string, { grade: string; note: string }> | null {
  const result: Record<string, { grade: string; note: string }> = {};
  let found = false;
  for (const attrName of ATTR_NAMES) {
    const regex = new RegExp(`(?:[-*]\\s*)?${attrName}[：:]\\s*([A-Za-z+~\\s]+?)(?:[（(\\s]|$)`, 'u');
    const lineMatch = content.match(regex);
    if (lineMatch) {
      const raw = lineMatch[1].trim();
      const afterAttr = content.substring((lineMatch.index ?? 0) + lineMatch[0].length);
      const noteMatch = afterAttr.match(/^[（(]([^）)]+)[）)]/);
      result[attrName] = {
        grade: raw,
        note: noteMatch ? noteMatch[1].trim() : '',
      };
      found = true;
    }
  }
  return found ? result : null;
}

const magicAbilityMap = ref<Map<string, Record<string, { grade: string; note: string }>>>(new Map());
const worldbookProtectedNames = ref<Set<string>>(new Set());

function resolveAbilityForGirl(
  key: string,
  girl: Record<string, unknown>,
): Record<string, { grade: string; note: string }> | null {
  const trueName = (girl.真名 as string)?.trim();
  const aliasToCheck = trueName && trueName !== '???' ? trueName : key.trim();
  const map = magicAbilityMap.value;
  if (map.has(aliasToCheck)) return map.get(aliasToCheck)!;
  for (const [mapKey, val] of map) {
    if (mapKey === aliasToCheck) return val;
  }
  for (const [mapKey, val] of map) {
    if (aliasToCheck.includes(mapKey) || mapKey.includes(aliasToCheck)) return val;
  }
  return null;
}

onMounted(async () => {
  try {
    const wbNames = getCharWorldbookNames('current');
    const primaryName = wbNames?.primary;
    if (!primaryName) return;
    const entries = await getWorldbook(primaryName);
    if (!Array.isArray(entries)) return;

    const byTrueName = new Map<string, { 常态: boolean; 堕落: boolean }>();
    for (const entry of entries) {
      const name = typeof entry?.name === 'string' ? entry.name : '';
      const match = name.match(/^\[角色\]\s+(.+?)-(魔法少女|堕落魔法少女)$/);
      if (!match) continue;
      const trueName = match[1].trim();
      const type = match[2];
      const existing = byTrueName.get(trueName) ?? { 常态: false, 堕落: false };
      if (type === '魔法少女') existing.常态 = true;
      else existing.堕落 = true;
      byTrueName.set(trueName, existing);
    }

    const protectedSet = new Set<string>();
    byTrueName.forEach((pair, trueName) => {
      // 任何形态存在于世界书即为内置, 禁止移除
      if (pair.常态 || pair.堕落) protectedSet.add(trueName);
    });
    worldbookProtectedNames.value = expandProtectedNames(protectedSet);

    const attrMap = new Map<string, Record<string, { grade: string; note: string }>>();
    for (const entry of entries) {
      const entryName = typeof entry?.name === 'string' ? entry.name : '';
      const nameMatch = entryName.match(/^\[角色\]\s+(.+?)-(魔法少女|堕落魔法少女)$/);
      if (!nameMatch || !entry.content) continue;
      const entryTrueName = nameMatch[1].trim();
      const attrs = parseMagicAbility(entry.content);
      if (attrs) attrMap.set(entryTrueName, attrs);
    }
    magicAbilityMap.value = attrMap;
  } catch {
    /* gracefully ignore */
  }
});

// ── State ──
const PREF_FILTER = 'msp_v5:archive_filter';
function getFilter(): Filter {
  try {
    const v = localStorage.getItem(PREF_FILTER);
    return v === 'normal' || v === 'fallen' ? v : 'all';
  } catch {
    return 'all';
  }
}

const filter = ref<Filter>(getFilter());
const expandedKey = ref<string>('');
const selectGirlEvent = inject<Ref<string | null>>('selectGirlEvent', ref(null));

watchEffect(() => {
  const n = selectGirlEvent?.value;
  if (n) expandedKey.value = n;
});

function setFilter(f: Filter) {
  filter.value = f;
  try {
    localStorage.setItem(PREF_FILTER, f);
  } catch {
    /* noop */
  }
}

// ── Girl list ──
interface GirlItem {
  key: string;
  magicName: string;
  trueName: string;
  displayName: string;
  exposed: boolean;
  fallen: boolean;
  protected: boolean;
  typeLabel: string;
  toneClass: 'normal' | 'fallen';
  magicCurrent: number;
  magicMax: number;
  magicPercent: number;
  stage: ReturnType<typeof manaStage>;
  attitude: string;
  attitudeToneClass: string;
  hasUnresolvedKnots: boolean;
  unresolvedKnots: { name: string; desc: string }[];
  resolvedKnots: { name: string; desc: string }[];
  magicAbility: Record<string, { grade: string; note: string }> | null;
}

const girlsList = computed<GirlItem[]>(() => {
  const girls = ((store.data as Record<string, unknown>).魔法少女 as Record<string, Record<string, unknown>>) ?? {};

  return Object.entries(girls)
    .map(([key, g]) => {
      const magicMax = Number(g.魔力上限) || 100;
      const magicCurrent = Number(g.魔力) || 0;
      const magicPercent = magicMax ? Math.round((magicCurrent / magicMax) * 100) : 0;
      const fallen = g.是否堕落 === true;
      const toneClass = fallen ? 'fallen' : 'normal';
      const stage = manaStage(magicPercent);

      const knots = (g.心结 as Record<string, { 描述: string; 是否解开: boolean }>) ?? {};
      const unresolvedKnots = Object.entries(knots)
        .filter(([, v]) => !v.是否解开)
        .map(([name, v]) => ({ name, desc: v.描述 || '???' }));
      const resolvedKnots = Object.entries(knots)
        .filter(([, v]) => v.是否解开)
        .map(([name, v]) => ({ name, desc: v.描述 || '' }));

      const exposed = g.暴露 === true;
      const rawTrueName = (g.真名 as string) || '???';
      const displayName = exposed ? rawTrueName : '???';

      return {
        key,
        magicName: (g.魔法名 as string) || '???',
        trueName: rawTrueName,
        displayName,
        exposed,
        fallen,
        protected: worldbookProtectedNames.value.has((g.真名 as string)?.trim() || key.trim()),
        typeLabel: fallen ? '堕落' : '常态',
        toneClass,
        magicCurrent,
        magicMax,
        magicPercent,
        stage,
        attitude: (g.对主角的态度 as string) || '陌生',
        attitudeToneClass: attitudeTone((g.对主角的态度 as string) || '陌生'),
        hasUnresolvedKnots: unresolvedKnots.length > 0,
        unresolvedKnots,
        resolvedKnots,
        magicAbility: resolveAbilityForGirl(key, g),
      };
    })
    .sort((a, b) => a.magicName.localeCompare(b.magicName, 'zh-Hans-CN'));
});

const filteredGirls = computed(() => {
  if (filter.value === 'fallen') return girlsList.value.filter(g => g.fallen);
  if (filter.value === 'normal') return girlsList.value.filter(g => !g.fallen);
  return girlsList.value;
});

function toggleExpand(key: string) {
  expandedKey.value = expandedKey.value === key ? '' : key;
}

// ── Knot inline CRUD ──
interface KnotDraft {
  girlKey: string;
  originalName: string;
  name: string;
  desc: string;
}

const knotDraft = reactive<KnotDraft>({
  girlKey: '',
  originalName: '',
  name: '',
  desc: '',
});
const knotEditing = ref(false);

function startAddKnot(girlKey: string) {
  knotDraft.girlKey = girlKey;
  knotDraft.originalName = '';
  knotDraft.name = '';
  knotDraft.desc = '';
  knotEditing.value = true;
}

function startEditKnot(girlKey: string, name: string, desc: string) {
  knotDraft.girlKey = girlKey;
  knotDraft.originalName = name;
  knotDraft.name = name;
  knotDraft.desc = desc;
  knotEditing.value = true;
}

function cancelKnotEdit() {
  knotEditing.value = false;
  knotDraft.girlKey = '';
  knotDraft.originalName = '';
  knotDraft.name = '';
  knotDraft.desc = '';
}

function saveKnot() {
  const name = knotDraft.name.trim();
  if (!name || !knotDraft.girlKey) return;

  const girls = (store.data as Record<string, unknown>).魔法少女 as Record<string, Record<string, unknown>>;
  const girl = girls[knotDraft.girlKey];
  if (!girl) return;

  const knots = (girl.心结 as Record<string, { 描述: string; 是否解开: boolean }>) ?? {};
  if (knotDraft.originalName && knotDraft.originalName !== name) {
    delete knots[knotDraft.originalName];
  }
  knots[name] = {
    描述: knotDraft.desc.trim() || '???',
    是否解开: knots[name]?.是否解开 ?? false,
  };
  cancelKnotEdit();
}

function toggleKnotResolved(girlKey: string, knotName: string) {
  const girls = (store.data as Record<string, unknown>).魔法少女 as Record<string, Record<string, unknown>>;
  const girl = girls[girlKey];
  if (!girl) return;
  const knots = (girl.心结 as Record<string, { 是否解开: boolean }>) ?? {};
  if (knots[knotName]) {
    knots[knotName].是否解开 = !knots[knotName].是否解开;
  }
}

function deleteKnot(girlKey: string, knotName: string) {
  const girls = (store.data as Record<string, unknown>).魔法少女 as Record<string, Record<string, unknown>>;
  const girl = girls[girlKey];
  if (!girl) return;
  const knots = (girl.心结 as Record<string, { 是否解开: boolean }>) ?? {};
  delete knots[knotName];
  if (knotDraft.originalName === knotName) cancelKnotEdit();
}

// ── Delete girl (非内置可移除) ──
const deleteConfirmKey = ref<string>('');

function askDelete(key: string) {
  deleteConfirmKey.value = key;
}
function cancelDelete() {
  deleteConfirmKey.value = '';
}
function confirmDelete() {
  const girls = (store.data as Record<string, unknown>).魔法少女 as Record<string, Record<string, unknown>>;
  const key = deleteConfirmKey.value;
  if (key && girls[key]) {
    delete girls[key];
    if (expandedKey.value === key) expandedKey.value = '';
  }
  cancelDelete();
}
</script>

<template>
  <div class="archive">
    <!-- Toolbar -->
    <div v-if="girlsList.length" class="toolbar">
      <span class="count mono">{{ girlsList.length }} 名</span>
      <div class="filter-group" role="group" aria-label="过滤">
        <button
          v-for="f in (['all', 'normal', 'fallen'] as Filter[])"
          :key="f"
          class="filter-btn"
          :class="{ active: filter === f, fallen: f === 'fallen' }"
          type="button"
          @click="setFilter(f)"
        >
          {{ f === 'all' ? '全部' : f === 'normal' ? '常态' : '堕落' }}
        </button>
      </div>
    </div>

    <!-- Empty -->
    <div v-if="!girlsList.length" class="empty">
      <div class="empty-icon" aria-hidden="true">◇</div>
      <div class="empty-text">尚未收录任何魔法少女</div>
    </div>
    <div v-else-if="!filteredGirls.length" class="empty">
      <div class="empty-text">该筛选下无记录</div>
    </div>

    <!-- List (compact list, expandable) -->
    <div v-else class="list">
      <ChamferPanel
        v-for="g in filteredGirls"
        :key="g.key"
        :variant="g.toneClass === 'fallen' ? 'fallen' : 'default'"
        density="compact"
        class="girl-row"
        :class="{ expanded: expandedKey === g.key }"
        as="article"
      >
        <button
          class="row-trigger"
          type="button"
          :aria-expanded="expandedKey === g.key"
          @click="toggleExpand(g.key)"
        >
          <CrystalOrb
            compact
            :percent="g.magicPercent"
            :current="g.magicCurrent"
            :max="g.magicMax"
            :stage="g.stage"
            :fallen="g.fallen"
          />
          <div class="row-info">
            <div class="row-name">
              {{ g.magicName }}
              <span v-if="g.hasUnresolvedKnots" class="knot-pip" title="存在未解决心结" />
            </div>
            <div class="row-meta">
              <StatusBadge :tone="g.toneClass === 'fallen' ? 'fallen' : 'accent'" size="xs">
                {{ g.typeLabel }}
              </StatusBadge>
              <StatusBadge :tone="(g.attitudeToneClass as any)" size="xs">{{ g.attitude }}</StatusBadge>
            </div>
          </div>
          <svg
            class="expand-ico"
            viewBox="0 0 24 24"
            :class="{ rotated: expandedKey === g.key }"
            aria-hidden="true"
          >
            <path d="M6 9l6 6 6-6" stroke="currentColor" stroke-width="2" fill="none" stroke-linecap="round" />
          </svg>
        </button>

        <!-- Expanded detail -->
        <Transition name="expand">
          <div v-if="expandedKey === g.key" class="girl-detail">
            <!-- Hero block -->
            <div class="hero">
              <div class="hero-eyebrow mono">{{ g.fallen ? 'FALLEN' : 'CRYSTAL' }} · MG</div>
              <div class="hero-name">{{ g.magicName }}</div>
              <div class="hero-true">
                真名 <strong class="mono">{{ g.displayName }}</strong>
                <StatusBadge
                  v-if="!g.exposed"
                  tone="default"
                  size="xs"
                  dashed
                  style="margin-left: 6px"
                >
                  未暴露
                </StatusBadge>
              </div>
              <div class="hero-tags">
                <StatusBadge :tone="g.toneClass === 'fallen' ? 'fallen' : 'accent'" size="sm">
                  {{ g.typeLabel }}
                </StatusBadge>
                <StatusBadge :tone="(g.attitudeToneClass as any)" size="sm">{{ g.attitude }}</StatusBadge>
              </div>
            </div>

            <!-- Stats row: orb + radar -->
            <div class="stats-row" :class="{ 'no-radar': !g.magicAbility }">
              <div class="orb-cell">
                <CrystalOrb
                  :percent="g.magicPercent"
                  :current="g.magicCurrent"
                  :max="g.magicMax"
                  :stage="g.stage"
                  :fallen="g.fallen"
                />
              </div>
              <div v-if="g.magicAbility" class="radar-cell">
                <div class="radar-eyebrow mono">ABILITY · 八维</div>
                <AbilityGrid :data="g.magicAbility" />
              </div>
            </div>

            <!-- Knots -->
            <div class="knots-block">
              <div class="knots-head">
                <div class="knots-title">
                  心结
                  <span class="knots-count mono">
                    <span class="warn-num">{{ g.unresolvedKnots.length }}</span>
                    <span class="sep">/</span>
                    <span class="ok-num">{{ g.resolvedKnots.length }}</span>
                  </span>
                </div>
                <button
                  v-if="!knotEditing || knotDraft.girlKey !== g.key"
                  class="add-knot-btn"
                  type="button"
                  @click="startAddKnot(g.key)"
                >
                  <svg viewBox="0 0 24 24" aria-hidden="true">
                    <path d="M12 5v14M5 12h14" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" />
                  </svg>
                  新增
                </button>
              </div>

              <Transition name="slide">
                <div v-if="knotEditing && knotDraft.girlKey === g.key" class="knot-form">
                  <div class="form-head">
                    <span class="form-title">{{ knotDraft.originalName ? '编辑心结' : '新增心结' }}</span>
                    <button class="mini-btn" type="button" aria-label="取消" @click="cancelKnotEdit">
                      <svg viewBox="0 0 24 24" aria-hidden="true">
                        <path d="M6 6l12 12M18 6L6 18" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" />
                      </svg>
                    </button>
                  </div>
                  <label class="field">
                    <span class="field-label mono">名称</span>
                    <input
                      v-model="knotDraft.name"
                      class="field-input"
                      type="text"
                      placeholder="例如：对姐姐的愧疚"
                      @keydown.enter="saveKnot"
                      @keydown.escape="cancelKnotEdit"
                    >
                  </label>
                  <label class="field">
                    <span class="field-label mono">描述</span>
                    <textarea
                      v-model="knotDraft.desc"
                      class="field-input area"
                      placeholder="心结的具体描述…"
                      rows="2"
                      @keydown.escape="cancelKnotEdit"
                    />
                  </label>
                  <div class="form-actions">
                    <button
                      class="primary-btn"
                      type="button"
                      :disabled="!knotDraft.name.trim()"
                      @click="saveKnot"
                    >
                      保存
                    </button>
                    <button
                      v-if="knotDraft.originalName"
                      class="danger-btn"
                      type="button"
                      @click="deleteKnot(g.key, knotDraft.originalName)"
                    >
                      删除
                    </button>
                  </div>
                </div>
              </Transition>

              <div v-if="g.unresolvedKnots.length || g.resolvedKnots.length" class="knot-list">
                <article
                  v-for="k in g.unresolvedKnots"
                  :key="`u-${k.name}`"
                  class="knot-item unresolved"
                >
                  <button
                    class="knot-toggle"
                    type="button"
                    title="标记已解开"
                    aria-label="标记已解开"
                    @click="toggleKnotResolved(g.key, k.name)"
                  >
                    <span class="knot-check" />
                  </button>
                  <div class="knot-body" @click="startEditKnot(g.key, k.name, k.desc)">
                    <div class="knot-name">{{ k.name }}</div>
                    <div class="knot-desc">{{ k.desc }}</div>
                  </div>
                  <div class="knot-tools">
                    <button class="mini-btn" type="button" title="编辑" aria-label="编辑" @click.stop="startEditKnot(g.key, k.name, k.desc)">
                      <svg viewBox="0 0 24 24" aria-hidden="true">
                        <path d="M5 19l1-5 12-12 4 4-12 12-5 1z" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linejoin="round" />
                      </svg>
                    </button>
                    <button class="mini-btn danger" type="button" title="删除" aria-label="删除" @click.stop="deleteKnot(g.key, k.name)">
                      <svg viewBox="0 0 24 24" aria-hidden="true">
                        <path d="M6 6l12 12M18 6L6 18" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" />
                      </svg>
                    </button>
                  </div>
                </article>

                <article
                  v-for="k in g.resolvedKnots"
                  :key="`r-${k.name}`"
                  class="knot-item resolved"
                >
                  <button
                    class="knot-toggle"
                    type="button"
                    title="重新激活"
                    aria-label="重新激活"
                    @click="toggleKnotResolved(g.key, k.name)"
                  >
                    <span class="knot-check checked">
                      <svg viewBox="0 0 24 24" aria-hidden="true">
                        <path d="M5 12l5 5L20 7" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round" />
                      </svg>
                    </span>
                  </button>
                  <div class="knot-body" @click="startEditKnot(g.key, k.name, k.desc)">
                    <div class="knot-name resolved-name">{{ k.name }}</div>
                    <div class="knot-desc resolved-desc">{{ k.desc || '该心结已解开。' }}</div>
                  </div>
                  <div class="knot-tools">
                    <button class="mini-btn" type="button" title="编辑" aria-label="编辑" @click.stop="startEditKnot(g.key, k.name, k.desc)">
                      <svg viewBox="0 0 24 24" aria-hidden="true">
                        <path d="M5 19l1-5 12-12 4 4-12 12-5 1z" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linejoin="round" />
                      </svg>
                    </button>
                    <button class="mini-btn danger" type="button" title="删除" aria-label="删除" @click.stop="deleteKnot(g.key, k.name)">
                      <svg viewBox="0 0 24 24" aria-hidden="true">
                        <path d="M6 6l12 12M18 6L6 18" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" />
                      </svg>
                    </button>
                  </div>
                </article>
              </div>

              <div v-else class="knots-empty">尚无心结记录</div>
            </div>

            <!-- Delete (非内置才能移除) -->
            <div v-if="!g.protected" class="delete-row">
              <Transition name="fade" mode="out-in">
                <div v-if="deleteConfirmKey !== g.key" key="ask" class="delete-ask">
                  <button class="delete-link" type="button" @click="askDelete(g.key)">
                    移除该档案
                  </button>
                </div>
                <div v-else key="confirm" class="delete-confirm">
                  <span class="confirm-text">确认移除 {{ g.magicName }}?</span>
                  <button class="danger-btn" type="button" @click="confirmDelete">确认</button>
                  <button class="ghost-btn" type="button" @click="cancelDelete">取消</button>
                </div>
              </Transition>
            </div>
          </div>
        </Transition>
      </ChamferPanel>
    </div>
  </div>
</template>

<style scoped>
