  display: flex;
  flex-direction: column;
  gap: 10px;
}

.toolbar {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 0 2px;
}

.count {
  font-size: 12px;
  color: var(--ink-weak);
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

