<script setup lang="ts">
import { computed } from 'vue';

type Stage = 'surge' | 'high' | 'steady' | 'low' | 'empty';

const props = withDefaults(
  defineProps<{
    percent: number;
    current: number;
    max: number;
    stage: Stage;
    fallen: boolean;
    compact?: boolean;
  }>(),
  {
    compact: false,
  },
);

let _uid = 0;
const uid = ++_uid;
const ID = (s: string) => `crystal-${uid}-${s}`;

// ViewBox - 加宽以容纳八面体 + 文本
const VB_W = 120;
const VB_H = 132;
const TOP = 12;
const BOT = 118;
const FILL_SPAN = BOT - TOP;

// 八面体宝石轮廓 (顶部 table + 冠部 + 腰围 + 底部尖端)
// 腰围位于 y=44~58 是最宽处 (x=8~92, 宽 84), 适合放文字
const gemPath = 'M36,12 L84,12 L108,44 L108,58 L60,118 L12,58 L12,44 Z';

// 切面线 (装饰)
const facetPaths = [
  'M36,12 L12,58', // 左肩
  'M84,12 L108,58', // 右肩
  'M36,12 L60,118', // 左冠 → 底尖
  'M84,12 L60,118', // 右冠 → 底尖
  'M12,44 L108,44', // 腰围上线
  'M60,12 L60,118', // 中轴 (微弱)
];

// 堕落裂纹
const crackPaths = [
  'M48,30 L56,52 L50,72 L60,92',
  'M72,28 L66,46 L74,66 L68,88',
  'M60,20 L56,38 L62,56 L58,76',
];

const fillY = computed(() => BOT - FILL_SPAN * (Math.max(0, Math.min(100, props.percent)) / 100));

const stageColors = computed(() => {
  const prefix = props.fallen ? 'crystal-fallen' : 'crystal-normal';
  const map: Record<Stage, { color: string; bright: string }> = {
    surge: { color: `var(--${prefix}-surge)`, bright: `var(--${prefix}-surge)` },
    high: { color: `var(--${prefix}-high)`, bright: `var(--${prefix}-high)` },
    steady: { color: `var(--${prefix}-steady)`, bright: `var(--${prefix}-steady)` },
    low: { color: `var(--${prefix}-low)`, bright: `var(--${prefix}-low)` },
    empty: { color: `var(--${prefix}-empty)`, bright: `var(--${prefix}-empty)` },
  };
  return map[props.stage];
});

const sizePx = computed(() => (props.compact ? 42 : 132));
const aspect = VB_H / VB_W;

const stageClass = computed(() => `s-${props.stage}`);
const toneClass = computed(() => (props.fallen ? 'fallen' : 'normal'));

// 文本缩放: 三位数时缩小
const bigFont = computed(() => {
  const digits = String(props.percent).length;
  if (digits >= 3) return 20;
  return 24;
});
</script>

<template>
  <div
    class="crystal"
    :class="[stageClass, toneClass, { compact }]"
    :style="{ width: sizePx + 'px' }"
  >
    <svg
      :viewBox="`0 0 ${VB_W} ${VB_H}`"
      :width="sizePx"
      :height="sizePx * aspect"
      xmlns="http://www.w3.org/2000/svg"
      overflow="visible"
    >
      <defs>
        <linearGradient :id="ID('fill')" x1="0" y1="1" x2="0" y2="0">
          <stop offset="0%" :stop-color="stageColors.color" stop-opacity="0.85" />
          <stop offset="60%" :stop-color="stageColors.bright" stop-opacity="0.95" />
          <stop offset="100%" :stop-color="stageColors.bright" stop-opacity="1" />
        </linearGradient>

        <linearGradient :id="ID('glaze')" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stop-color="rgba(255,255,255,0.35)" />
          <stop offset="40%" stop-color="rgba(255,255,255,0.08)" />
          <stop offset="100%" stop-color="rgba(255,255,255,0)" />
        </linearGradient>

        <clipPath :id="ID('clip')">
          <path :d="gemPath" />
        </clipPath>

        <filter :id="ID('glow')" x="-50%" y="-50%" width="200%" height="200%">
          <feGaussianBlur stdDeviation="2.2" />
        </filter>
      </defs>

      <!-- 光晕 -->
      <path
        v-if="!compact"
        :d="gemPath"
        class="halo"
        :filter="`url(#${ID('glow')})`"
        :fill="stageColors.bright"
      />

      <!-- 宝石底色框 -->
      <path :d="gemPath" class="frame" />

      <!-- 填充 (裁剪到宝石内) -->
      <g :clip-path="`url(#${ID('clip')})`">
        <rect
          class="fill-rect"
          :x="0"
          :y="fillY"
          :width="VB_W"
          :height="VB_H - fillY"
          :fill="`url(#${ID('fill')})`"
        />
        <!-- 填充表面高光 -->
        <rect
          v-if="percent > 0 && percent < 100"
          class="surface-line"
          :x="0"
          :y="fillY - 0.6"
          :width="VB_W"
          :height="1.4"
        />
        <!-- 玻璃质感 -->
        <rect :x="0" :y="0" :width="VB_W" :height="VB_H" :fill="`url(#${ID('glaze')})`" />
      </g>

      <!-- 切面线 -->
      <g v-if="!compact" class="facets" :clip-path="`url(#${ID('clip')})`">
        <path v-for="(d, i) in facetPaths" :key="i" :d="d" />
      </g>

      <!-- 堕落裂纹 -->
      <g v-if="fallen && !compact" class="cracks" :clip-path="`url(#${ID('clip')})`">
        <path v-for="(d, i) in crackPaths" :key="`c${i}`" :d="d" />
      </g>

      <!-- 重绘外框 (顶部清晰边缘) -->
      <path :d="gemPath" class="outline-top" />

      <!-- 文字 (紧凑模式: 仅百分比; 完整模式: 百分比 + 数值, 都在腰围宽区) -->
      <template v-if="compact">
        <text
          :x="VB_W / 2"
          :y="VB_H / 2 + 1"
          class="compact-num"
          text-anchor="middle"
          dominant-baseline="central"
        >
          {{ percent }}
        </text>
      </template>
      <template v-else>
        <text
          :x="VB_W / 2"
          :y="40"
          class="big-num"
          :style="{ fontSize: bigFont + 'px' }"
          text-anchor="middle"
          dominant-baseline="central"
        >
          {{ percent }}<tspan class="pct">%</tspan>
        </text>
        <text
          :x="VB_W / 2"
          :y="58"
          class="sub-num"
          text-anchor="middle"
          dominant-baseline="central"
        >
          {{ current }}/{{ max }}
        </text>
      </template>
    </svg>
  </div>
</template>

<style scoped>
