  position: relative;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

.frame {
  fill: var(--panel-soft);
  stroke: var(--border-strong);
  stroke-width: 1.4;
  filter: drop-shadow(0 0 4px var(--accent-glow));
}

.fallen .frame {
  stroke: var(--fallen-glow);
  filter: drop-shadow(0 0 4px var(--fallen-glow));
}

.halo {
  opacity: 0.18;
}

.fill-rect {
  transition: y 0.5s var(--ease-out);
}

.surface-line {
  fill: rgba(255, 255, 255, 0.6);
  filter: drop-shadow(0 0 4px rgba(255, 255, 255, 0.5));
}

.facets path {
  fill: none;
  stroke: rgba(255, 255, 255, 0.18);
  stroke-width: 0.5;
}

.outline-top {
  fill: none;
  stroke: var(--accent);
  stroke-width: 1.4;
  filter: drop-shadow(0 0 3px var(--accent-glow));
  pointer-events: none;
}
.fallen .outline-top {
  stroke: var(--fallen);
  filter: drop-shadow(0 0 3px var(--fallen-glow));
}

.cracks path {
  fill: none;
  stroke: rgba(0, 0, 0, 0.55);
  stroke-width: 0.7;
  stroke-dasharray: 3 1.5;
  opacity: 0.6;
}

/* 阶段脉冲 */
.s-surge .fill-rect {
  animation: pulse-strong 1.8s ease-in-out infinite;
}
.s-high .fill-rect {
  animation: pulse-soft 2.4s ease-in-out infinite;
}
.s-empty .fill-rect {
  animation: flicker 0.9s ease-in-out infinite;
}

@keyframes pulse-strong {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.82; }
}
@keyframes pulse-soft {
  0%, 100% { opacity: 0.95; }
  50% { opacity: 0.78; }
}
@keyframes flicker {
  0%, 100% { opacity: 0.6; }
  20% { opacity: 0.3; }
  40% { opacity: 0.75; }
  60% { opacity: 0.25; }
  80% { opacity: 0.7; }
}

/* 文字样式 */
.compact-num {
  font-family: var(--font-mono);
  font-size: 15px;
  font-weight: 800;
  fill: var(--ink-strong);
  letter-spacing: 0.02em;
}

.big-num {
  font-family: var(--font-mono);
  font-weight: 800;
  fill: var(--ink-bright);
  letter-spacing: 0.02em;
  paint-order: stroke fill;
  stroke: rgba(0, 0, 0, 0.4);
  stroke-width: 2.5px;
}

.big-num .pct {
  font-size: 0.6em;
  opacity: 0.85;
  margin-left: 1px;
}

.sub-num {
  font-family: var(--font-mono);
  font-size: 11px;
  font-weight: 600;
  fill: var(--ink-bright);
  letter-spacing: 0.02em;
  paint-order: stroke fill;
  stroke: rgba(0, 0, 0, 0.5);
  stroke-width: 2px;
}

.crystal.compact {
  --shadow-card: none;
}
</style>
