<script setup lang="ts">
interface Section {
  id: string;
  label: string;
}

defineProps<{
  sections: Section[];
  modelValue: string;
}>();

const emit = defineEmits<{
  'update:modelValue': [value: string];
}>();

function select(id: string) {
  emit('update:modelValue', id);
}
</script>

<template>
  <nav class="section-nav" role="tablist" aria-label="分区切换">
    <button
      v-for="s in sections"
      :key="s.id"
      class="nav-item"
      :class="{ active: modelValue === s.id }"
      type="button"
      role="tab"
      :aria-selected="modelValue === s.id"
      @click="select(s.id)"
    >
      <span class="nav-label">{{ s.label }}</span>
      <span class="nav-mark" aria-hidden="true" />
    </button>
  </nav>
</template>

